#include<cstdio>
#include<cstring>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define drep(a,b,c) for(int c(a);c>=(b);--c)
namespace MF
{
	const int N=2e6+10,M=1e7+10,INF=0x3f3f3f3f;
	int head[N],des[M],nxt[M],cgt=1,s,t,S,dep[N],que[N],cap[M],H,T,h2[N];bool vis[N];
	inline void Clear(){memset(head,0,(S+2)<<2);cgt=1;S=0;}
	inline void ins(const int &x,const int &y,const int &c=1)
	{
		if(!x||!y)return;
		nxt[++cgt]=head[x];des[head[x]=cgt]=y;cap[cgt]=c;
		nxt[++cgt]=head[y];des[head[y]=cgt]=x;cap[cgt]=0;
	}
	inline bool bfs()
	{
		memset(dep,0,(S+2)<<2);dep[que[H=T=0]=s]=1;
		while(H<=T){int u=que[H++];for(int i(head[u]);i;i=nxt[i])if(cap[i]&&!dep[des[i]])dep[que[++T]=des[i]]=dep[u]+1;} return dep[t];
	}
	inline int dfs(const int &u=s,int in=INF)
	{
		if(u==t)return in;int out=0;
		for(int &i=h2[u];i;i=nxt[i])
		{
			int v=des[i];if(cap[i]&&dep[v]==dep[u]+1)
			{
				int tmp=dfs(v,cap[i]<in?cap[i]:in);
				out+=tmp;cap[i]-=tmp;cap[i^1]+=tmp;if(!(in-=tmp))break;
			}
		}
		return out?out:dep[u]=0;
	}
	inline int dinic()
	{
		int res=0;while(bfs())memcpy(h2,head,(S+2)<<2),res+=dfs();return res;
	}
	inline void Init(){memset(head,0,(S+2)<<2);S=0;cgt=1;} 
}
using MF::ins;using MF::S;using MF::s;using MF::t;using MF::dinic;

inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
const int N=210;char a[N][N];int n,m,ans;int idx[N][N][2];
//inline void debug(int op,int x,int y,int z,int xx,int yy,int zz)
//{
//	printf("Case %d ::  (%d,%d,%d)  -->  (%d,%d,%d)\n",op,x,y,z,xx,yy,zz);
//}
int main()
{
	n=read();m=read();rep(1,n,i)scanf("%s",a[i]+1);
	rep(1,n,i)rep(1,m,j)ans+=(a[i][j]=='#');s=++S;t=++S;
	rep(1,n,i)rep(1,m,j)if(a[i][j]=='#')
	{
		if(a[i-1][j]=='#')
		{
			ins(s,idx[i][j][0]=++S,1);
			if(idx[i-1][j][1])
			{
//				if(!idx[i][j][0])ins(s,idx[i][j][0]=++S,1);
				ins(idx[i][j][0],idx[i-1][j][1],1);//debug(1,i,j,0,i-1,j,1);
			}
			if(idx[i-1][j+1][1])
			{
//				if(!idx[i][j][0])ins(s,idx[i][j][0]=++S,1) 
				ins(idx[i][j][0],idx[i-1][j+1][1],1);//debug(2,i,j,0,i-1,j+1,1);
			}
		}
		if(a[i][j-1]=='#')
		{
			ins(idx[i][j][1]=++S,t,1);
			if(idx[i][j-1][0])
			{
//				if(!idx[j][1])ins(idx[i][j][1]=++S,t,1);
				ins(idx[i][j-1][0],idx[i][j][1],1);//debug(3,i,j-1,0,i,j,1);
			}
			if(idx[i][j][0])
			{
//				if(!idx[i][j][1])ins(idx[i][j][1]=++S,t,1);
				ins(idx[i][j][0],idx[i][j][1],1);//debug(4,i,j,0,i,j,1);
			}
		}
	}
//	printf("QAQ S :: %d\n",S-2);
	int res=(S-2)-dinic();printf("%d\n",ans-res);
}
